const original = $('Montar contexto do lead').first().json;

function parseObject(value) {
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (error) {
      return { message: value };
    }
  }

  if (value && typeof value === 'object') {
    return value;
  }

  return {};
}

function asTrimmedString(value) {
  return typeof value === 'string' && value.trim() ? value.trim() : null;
}

function uniqueStrings(value) {
  if (!Array.isArray(value)) return [];
  return Array.from(new Set(value.map((item) => asTrimmedString(item)).filter(Boolean)));
}

function normalizeEmail(value) {
  const email = asTrimmedString(value);
  if (!email) return null;

  const normalized = email.toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(normalized) ? normalized : null;
}

function normalizeFullName(value) {
  const name = asTrimmedString(value);
  if (!name) return null;

  return name
    .replace(/\s+/g, ' ')
    .split(' ')
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
    .join(' ');
}

function normalizeIntent(value) {
  const intent = asTrimmedString(value);
  if (!intent) return 'unknown';

  const normalized = intent.toLowerCase();
  if (['buy', 'sell', 'rent', 'unknown'].includes(normalized)) {
    return normalized;
  }

  return 'unknown';
}

function normalizeRelationshipType(value) {
  return value === 'owner' ? 'owner' : 'interested';
}

function normalizePropertyLinks(value) {
  if (!Array.isArray(value)) return [];

  const dedupe = new Map();
  for (const item of value) {
    if (!item || typeof item !== 'object' || Array.isArray(item)) continue;

    const reference = asTrimmedString(item.reference);
    if (!reference) continue;

    const relationshipType = normalizeRelationshipType(item.relationship_type);
    const notes = asTrimmedString(item.notes);
    const key = `${reference.toLowerCase()}::${relationshipType}`;

    if (!dedupe.has(key)) {
      dedupe.set(key, {
        reference,
        relationship_type: relationshipType,
        notes,
      });
    }
  }

  return Array.from(dedupe.values());
}

function normalizeWhatsAppFormatting(value) {
  let text = asTrimmedString(value) || '';
  if (!text) return '';

  text = text.replace(/\r\n/g, '\n');
  text = text.replace(/<br\s*\/?>/gi, '\n');
  text = text.replace(/<[^>]+>/g, '');
  text = text.replace(/```([\s\S]*?)```/g, '$1');
  text = text.replace(/`([^`]+)`/g, '$1');
  text = text.replace(/^\s{0,3}#{1,6}\s+/gm, '');
  text = text.replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, '$1: $2');
  text = text.replace(/\*\*\*([^*]+)\*\*\*/g, '*$1*');
  text = text.replace(/\*\*([^*]+)\*\*/g, '*$1*');
  text = text.replace(/__([^_]+)__/g, '_$1_');
  text = text.replace(/~~([^~]+)~~/g, '~$1~');
  text = text.replace(/^\s*[\u2022*+]\s+/gm, '- ');
  text = text.replace(/[ \t]+\n/g, '\n');
  text = text.replace(/\n{3,}/g, '\n\n');

  return text.trim();
}

function normalizeDeliveryType(value) {
  const normalized = asTrimmedString(value)?.toLowerCase();
  if (normalized === 'image' || normalized === 'document') {
    return normalized;
  }
  return 'text';
}

function normalizeMediaUrl(value, deliveryType) {
  const url = asTrimmedString(value);
  if (!url) return null;

  if (/^https?:\/\//i.test(url)) {
    return url;
  }

  if (deliveryType === 'image' && /^data:image\//i.test(url)) {
    return url;
  }

  if (deliveryType === 'document' && /^data:application\//i.test(url)) {
    return url;
  }

  return null;
}

function normalizeMediaUrls(values, deliveryType) {
  const list = Array.isArray(values) ? values : [values];
  const dedupe = new Set();
  const output = [];

  for (const entry of list.flat()) {
    let candidate = entry;

    if (candidate && typeof candidate === 'object' && !Array.isArray(candidate)) {
      candidate = candidate.url ?? candidate.media_url ?? candidate.image_url ?? null;
    }

    const normalized = normalizeMediaUrl(candidate, deliveryType);
    if (!normalized || dedupe.has(normalized)) continue;

    dedupe.add(normalized);
    output.push(normalized);
  }

  return output;
}

function normalizeFileName(value, deliveryType) {
  const raw = asTrimmedString(value);
  if (!raw) {
    return deliveryType === 'document' ? 'arquivo.pdf' : null;
  }

  return raw.replace(/[\\/]/g, '-').slice(0, 120);
}

let response = parseObject($json.output ?? $json);
if (response && typeof response.output === 'string') {
  response = parseObject(response.output);
}

const message = normalizeWhatsAppFormatting(
  asTrimmedString(response?.message) ||
  asTrimmedString(response?.response) ||
  asTrimmedString(response?.text) ||
  'Oi! Posso te ajudar. Você está buscando comprar, vender ou alugar?'
);

const classification = ['HOT', 'WARM', 'COLD', 'NAO_APLICAVEL'].includes(response?.classification)
  ? response.classification
  : 'NAO_APLICAVEL';

const rawUpdates = response?.profile_updates && typeof response.profile_updates === 'object' && !Array.isArray(response.profile_updates)
  ? response.profile_updates
  : {};

const propertyLinks = normalizePropertyLinks(rawUpdates.property_links).slice(0, 5);

const rawDelivery = response?.delivery && typeof response.delivery === 'object' && !Array.isArray(response.delivery)
  ? response.delivery
  : {};

const requestedDeliveryType = normalizeDeliveryType(rawDelivery.type);
const mediaUrls = normalizeMediaUrls([
  rawDelivery.urls,
  rawDelivery.media_urls,
  rawDelivery.images,
  rawDelivery.url,
  rawDelivery.media_url,
  rawDelivery.image_url,
  rawDelivery.document_url,
], requestedDeliveryType);
const mediaCaption = normalizeWhatsAppFormatting(
  asTrimmedString(rawDelivery.caption) ||
  asTrimmedString(rawDelivery.message) ||
  ''
);
const mediaFileName = normalizeFileName(
  rawDelivery.file_name ?? rawDelivery.filename ?? rawDelivery.fileName,
  requestedDeliveryType
);
const deliveryReference =
  asTrimmedString(rawDelivery.reference) ||
  asTrimmedString(rawDelivery.property_reference) ||
  asTrimmedString(rawDelivery.property) ||
  (propertyLinks[0]?.reference ?? null);
const deliveryType = requestedDeliveryType !== 'text' && (mediaUrls.length > 0 || !!deliveryReference)
  ? requestedDeliveryType
  : 'text';

const scoreDefaults = {
  HOT: 20,
  WARM: 10,
  COLD: 3,
  NAO_APLICAVEL: 0,
};

const explicitScore = Number(rawUpdates.score_delta);
const scoreDelta = Number.isFinite(explicitScore)
  ? Math.max(0, Math.round(explicitScore))
  : scoreDefaults[classification] || 0;

return [{
  json: {
    instance: original.instance || 'mariana-sdr',
    agent_id: original.agent_id || 'mariana-sdr',
    agent_label: original.agent_label || 'Mariana Silva',
    remote_jid: original.remote_jid,
    thread_id: original.thread_id,
    person_id: original.person_id || null,
    phone: original.phone,
    provider_message_id: original.provider_message_id || null,
    text: String(message).trim(),
    should_reply: response?.should_reply !== false,
    classification,
    delivery_type: deliveryType,
    delivery_reference: deliveryReference,
    media_url: mediaUrls[0] || null,
    media_urls: deliveryType !== 'text' ? mediaUrls : [],
    media_caption: mediaCaption || null,
    media_file_name: mediaFileName,
    profile_updates: {
      full_name: normalizeFullName(rawUpdates.full_name),
      email: normalizeEmail(rawUpdates.email),
      intent: normalizeIntent(rawUpdates.intent),
      score_delta: scoreDelta,
      notes_ai: uniqueStrings(rawUpdates.notes_ai).slice(0, 4),
      notes_internal: uniqueStrings(rawUpdates.notes_internal).slice(0, 4),
      property_links: propertyLinks,
    },
  },
}];

function esc(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/\\/g, '\\\\').replace(/'/g, "''")}'`;
}

function escJson(value) {
  const json = JSON.stringify(value ?? {});
  return `${esc(json)}::jsonb`;
}

function normalizeEmail(value) {
  if (typeof value !== 'string' || !value.trim()) return null;
  const email = value.trim().toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? email : null;
}

function normalizeFullName(value) {
  if (typeof value !== 'string' || !value.trim()) return null;

  return value
    .trim()
    .replace(/\s+/g, ' ')
    .split(' ')
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
    .join(' ');
}

const replyData = $('Prepare Reply').first().json;
const sendResult = $json;

if (replyData.delivery_type === 'image' && Number(sendResult.media_index ?? 0) > 0) {
  return [{
    json: {
      ...sendResult,
      outbound_sql: 'SELECT 1 AS skipped_persist;',
    },
  }];
}

const updates = replyData.profile_updates && typeof replyData.profile_updates === 'object' && !Array.isArray(replyData.profile_updates)
  ? replyData.profile_updates
  : {};
const nowIso = new Date().toISOString();
const author = replyData.agent_label || replyData.agent_id || 'Mariana Silva';
const extractedFullName = normalizeFullName(updates.full_name);
const extractedEmail = normalizeEmail(updates.email);
const extractedIntent = ['buy', 'sell', 'rent', 'unknown'].includes(updates.intent) ? updates.intent : 'unknown';
const scoreDelta = Number.isFinite(Number(updates.score_delta)) ? Math.max(0, Math.round(Number(updates.score_delta))) : 0;
const propertyLinks = Array.isArray(updates.property_links) ? updates.property_links : [];

function createNote(content, visibility) {
  return {
    id: `note-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    content,
    visibility,
    author,
    createdAt: nowIso,
    updatedAt: nowIso,
  };
}

const notesToAppend = [
  ...(Array.isArray(updates.notes_ai) ? updates.notes_ai : [])
    .map((item) => typeof item === 'string' ? item.trim() : '')
    .filter(Boolean)
    .map((content) => createNote(content, 'ai')),
  ...(Array.isArray(updates.notes_internal) ? updates.notes_internal : [])
    .map((item) => typeof item === 'string' ? item.trim() : '')
    .filter(Boolean)
    .map((content) => createNote(content, 'internal')),
];

const metadataPatch = {
  latest_real_estate_intent: extractedIntent,
  last_extracted_email: extractedEmail,
  qualification_source: 'whatsapp_ai',
  qualification_updated_at: nowIso,
  last_property_link_hints: propertyLinks,
  last_classification: replyData.classification || 'NAO_APLICAVEL',
};

const d = {
  ...replyData,
  send_result: sendResult,
};

const outboundSql = `
WITH payload AS (
  SELECT
    ${esc(d.thread_id)}::text AS thread_id,
    ${esc(d.agent_label || d.agent_id || 'Agente')}::text AS agent_label,
    ${esc(d.text)}::text AS message_text,
    ${esc(d.person_id || null)}::uuid AS person_id,
    ${esc(extractedFullName)}::text AS extracted_full_name,
    ${esc(extractedEmail)}::text AS extracted_email,
    ${esc(extractedIntent)}::text AS extracted_intent,
    ${scoreDelta}::integer AS score_delta,
    ${escJson(notesToAppend)} AS notes_to_append,
    ${escJson(propertyLinks)} AS property_links,
    ${escJson(metadataPatch)} AS metadata_patch,
    ${esc(d.provider_message_id || null)}::text AS provider_message_id,
    ${esc(nowIso)}::timestamptz AS executed_at
),
inserir_saida AS (
  INSERT INTO public.chat_messages (
    thread_id,
    agent,
    role,
    content,
    is_system,
    created_at
  )
  SELECT
    payload.thread_id,
    payload.agent_label,
    'AI Agent',
    payload.message_text,
    false,
    now()
  FROM payload
  RETURNING id
),
atualizar_thread AS (
  UPDATE public.chat_threads
  SET
    preview = (SELECT message_text FROM payload),
    unread = false,
    last_message_at = now(),
    updated_at = now()
  WHERE thread_id = (SELECT thread_id FROM payload)
  RETURNING person_id
),
pessoa_resolvida AS (
  SELECT COALESCE((SELECT person_id FROM payload), (SELECT person_id FROM atualizar_thread LIMIT 1)) AS person_id
),
notas_existentes AS (
  SELECT
    p.id,
    CASE
      WHEN jsonb_typeof(COALESCE(p.metadata, '{}'::jsonb)->'lead_notes') = 'array'
        THEN COALESCE(p.metadata, '{}'::jsonb)->'lead_notes'
      ELSE '[]'::jsonb
    END AS lead_notes,
    p.roles,
    p.metadata
  FROM public.people p
  WHERE p.id = (SELECT person_id FROM pessoa_resolvida)
),
atualizar_pessoa AS (
  UPDATE public.people p
  SET
    full_name = COALESCE((SELECT extracted_full_name FROM payload), NULLIF(p.full_name, '')),
    email = COALESCE((SELECT extracted_email FROM payload), p.email),
    crm_score = COALESCE(p.crm_score, 0) + (SELECT score_delta FROM payload),
    last_interaction_preview = (SELECT message_text FROM payload),
    crm_unread = false,
    roles = (
      SELECT COALESCE(array_agg(DISTINCT role_value), ARRAY[]::public.person_role[])
      FROM unnest(
        COALESCE(p.roles, ARRAY[]::public.person_role[])
        || CASE WHEN (SELECT extracted_intent FROM payload) = 'buy' THEN ARRAY['buyer'::public.person_role] ELSE ARRAY[]::public.person_role[] END
        || CASE WHEN (SELECT extracted_intent FROM payload) = 'sell' THEN ARRAY['seller'::public.person_role] ELSE ARRAY[]::public.person_role[] END
      ) AS role_value
    ),
    metadata = jsonb_set(
      COALESCE(p.metadata, '{}'::jsonb) || (SELECT metadata_patch FROM payload),
      '{lead_notes}',
      COALESCE((SELECT lead_notes FROM notas_existentes), '[]'::jsonb) || COALESCE((SELECT notes_to_append FROM payload), '[]'::jsonb),
      true
    ),
    updated_at = now()
  WHERE p.id = (SELECT person_id FROM pessoa_resolvida)
  RETURNING p.id
),
property_link_rows AS (
  SELECT
    (SELECT person_id FROM pessoa_resolvida) AS person_id,
    NULLIF(BTRIM(item->>'reference'), '') AS reference,
    CASE WHEN item->>'relationship_type' = 'owner' THEN 'owner' ELSE 'interested' END AS relationship_type,
    NULLIF(BTRIM(item->>'notes'), '') AS notes
  FROM payload,
  LATERAL jsonb_array_elements(COALESCE((SELECT property_links FROM payload), '[]'::jsonb)) AS item
  WHERE (SELECT person_id FROM pessoa_resolvida) IS NOT NULL
    AND NULLIF(BTRIM(item->>'reference'), '') IS NOT NULL
),
matched_properties AS (
  SELECT DISTINCT ON (pl.person_id, p.id, pl.relationship_type)
    pl.person_id,
    p.id AS property_id,
    pl.relationship_type,
    pl.notes,
    jsonb_build_object(
      'reference', pl.reference,
      'provider_message_id', (SELECT provider_message_id FROM payload),
      'matched_at', (SELECT executed_at FROM payload)
    ) AS metadata
  FROM property_link_rows pl
  JOIN public.properties p
    ON lower(p.title) = lower(pl.reference)
    OR lower(COALESCE(p.slug, '')) = lower(pl.reference)
    OR lower(COALESCE(p.address, '')) = lower(pl.reference)
    OR lower(p.title) LIKE '%' || lower(pl.reference) || '%'
    OR lower(COALESCE(p.address, '')) LIKE '%' || lower(pl.reference) || '%'
  ORDER BY pl.person_id, p.id, pl.relationship_type,
    CASE
      WHEN lower(COALESCE(p.slug, '')) = lower(pl.reference) THEN 0
      WHEN lower(p.title) = lower(pl.reference) THEN 1
      WHEN lower(COALESCE(p.address, '')) = lower(pl.reference) THEN 2
      ELSE 3
    END,
    p.updated_at DESC
),
upsert_property_links AS (
  INSERT INTO public.person_properties (
    person_id,
    property_id,
    relationship_type,
    source,
    notes,
    metadata
  )
  SELECT
    matched.person_id,
    matched.property_id,
    matched.relationship_type,
    'whatsapp_ai',
    matched.notes,
    matched.metadata
  FROM matched_properties matched
  ON CONFLICT (person_id, property_id, relationship_type) DO UPDATE SET
    source = EXCLUDED.source,
    notes = COALESCE(EXCLUDED.notes, public.person_properties.notes),
    metadata = COALESCE(public.person_properties.metadata, '{}'::jsonb) || COALESCE(EXCLUDED.metadata, '{}'::jsonb),
    updated_at = now()
  RETURNING id
)
SELECT (SELECT id FROM inserir_saida) AS outbound_message_id;
`;

return [{
  json: {
    ...d,
    outbound_sql: outboundSql,
  },
}];

const body = $json.body || $json;
const data = body.data || {};
const key = data.key || {};
const message = data.message || {};

const eventName = String(body.event || '').toLowerCase();
const instance = String(body.instance || 'mariana-sdr');
const agentId = instance.split('/')[0] || instance;

const agentMap = {
  'mariana-sdr': 'Mariana Silva',
  'daniel-dir': 'Daniel Rocha',
  'camila-prop': 'Camila Rocha',
  'rafael-cs': 'Rafael Martins',
  'lucas-qual': 'Lucas Andrade'
};

const remoteJid = String(key.remoteJid || data.remoteJid || '');
const senderJid = String(body.sender || '');
const fromMe = key.fromMe === true;
const providerMessageId = String(key.id || data.id || '');
const pushName = String(data.pushName || body.pushName || '');
const messageTimestamp = data.messageTimestamp || body.date_time || null;
const source = String(data.source || body.source || 'whatsapp');

const text =
  message.conversation ||
  message.extendedTextMessage?.text ||
  message.imageMessage?.caption ||
  message.videoMessage?.caption ||
  message.documentMessage?.caption ||
  data.text ||
  '';

const cleanMessage = String(text || '').trim();

const phone = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '')
  .replace(/\D/g, '');

const instancePhone = senderJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '')
  .replace(/\D/g, '');

const threadId = remoteJid;

const isValidInboundMessage =
  eventName === 'messages.upsert' &&
  fromMe === false &&
  !!threadId &&
  !!cleanMessage &&
  phone !== instancePhone;

return [{
  json: {
    event: eventName,
    instance,
    agent_id: agentId,
    agent_label: agentMap[agentId] || agentId,
    remote_jid: remoteJid,
    thread_id: threadId,
    sender_jid: senderJid,
    phone,
    instance_phone: instancePhone,
    push_name: pushName,
    provider_message_id: providerMessageId,
    message_timestamp: messageTimestamp,
    source,
    message: cleanMessage,
    from_me: fromMe,
    is_valid_inbound_message: isValidInboundMessage
  }
}];

function parseJsonObject(value) {
  if (!value) return {};
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
    } catch (error) {
      return {};
    }
  }
  return typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function parseJsonArray(value) {
  if (!value) return [];
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }
  return Array.isArray(value) ? value : [];
}

function asString(value) {
  return typeof value === 'string' && value.trim() ? value.trim() : null;
}

function firstNonEmptyString() {
  for (const value of arguments) {
    const normalized = asString(value);
    if (normalized) return normalized;
  }
  return null;
}

function sanitizeHttpUrl(value) {
  const normalized = asString(value);
  if (!normalized) return null;
  if (normalized.startsWith('data:')) return null;
  if (normalized.length > 2000) return null;
  return /^https?:\/\//i.test(normalized) ? normalized : null;
}

function extractPhoneFromJid(value) {
  const raw = asString(value);
  if (!raw) return null;

  const digits = raw.split('@')[0].replace(/\D/g, '');
  return digits || null;
}

function normalizeLeadNotes(value) {
  const seen = new Set();

  return parseJsonArray(value)
    .filter((item) => item && typeof item === 'object' && !Array.isArray(item))
    .filter((item) => item.visibility === 'ai')
    .map((item) => ({
      id: item.id || null,
      content: typeof item.content === 'string' ? item.content.trim() : '',
      author: typeof item.author === 'string' ? item.author.trim() : null,
      updatedAt: typeof item.updatedAt === 'string' ? item.updatedAt : null,
    }))
    .filter((item) => item.content)
    .filter((item) => {
      const key = item.content.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(-8);
}

function normalizePropertyFeatures(value) {
  const features = parseJsonObject(value);
  return Object.fromEntries(
    Object.entries(features)
      .map(([key, entryValue]) => [key, asString(entryValue) || (Number.isFinite(Number(entryValue)) ? Number(entryValue) : null)])
      .filter(([, entryValue]) => entryValue !== null)
  );
}

function normalizePropertyOffers(value) {
  return parseJsonArray(value)
    .filter((item) => item && typeof item === "object" && !Array.isArray(item))
    .map((item) => ({
      id: asString(item.id) || null,
      offer_type: asString(item.offer_type || item.offerType),
      price: Number.isFinite(Number(item.price)) ? Number(item.price) : null,
      owner_price: Number.isFinite(Number(item.owner_price ?? item.ownerPrice)) ? Number(item.owner_price ?? item.ownerPrice) : null,
      commission_rate: Number.isFinite(Number(item.commission_rate ?? item.commissionRate)) ? Number(item.commission_rate ?? item.commissionRate) : null,
      is_primary: Boolean(item.is_primary ?? item.isPrimary),
    }))
    .filter((item) => item.offer_type && item.price !== null);
}

function normalizeLinkedProperties(value) {
  return parseJsonArray(value)
    .filter((item) => item && typeof item === "object" && !Array.isArray(item))
    .map((item) => ({
      property_id: asString(item.property_id) || null,
      title: asString(item.title),
      slug: asString(item.slug),
      public_url: asString(item.public_url),
      address: asString(item.address),
      price: Number.isFinite(Number(item.price)) ? Number(item.price) : null,
      property_offers: normalizePropertyOffers(item.property_offers),
      status: asString(item.status),
      description: asString(item.description)?.slice(0, 180) || null,
      cover_image: sanitizeHttpUrl(item.cover_image),
      relationship_type: asString(item.relationship_type),
      notes: asString(item.notes),
      source: asString(item.source),
      features: normalizePropertyFeatures(item.features),
    }))
    .filter((item) => item.property_id && item.status === "active")
    .slice(0, 8);
}

function normalizeActivePropertiesCatalog(value) {
  return parseJsonArray(value)
    .filter((item) => item && typeof item === "object" && !Array.isArray(item))
    .map((item) => ({
      id: asString(item.id) || null,
      title: asString(item.title),
      slug: asString(item.slug),
      public_url: asString(item.public_url),
      address: asString(item.address),
      price: Number.isFinite(Number(item.price)) ? Number(item.price) : null,
      property_offers: normalizePropertyOffers(item.property_offers),
      status: asString(item.status),
      cover_image: sanitizeHttpUrl(item.cover_image),
      features: normalizePropertyFeatures(item.features),
    }))
    .filter((item) => item.id && item.title && item.status === "active")
    .slice(0, 12);
}

function countTopValues(items, selector, limit = 5) {
  const counts = new Map();

  for (const item of items) {
    const value = asString(selector(item));
    if (!value) continue;
    counts.set(value, (counts.get(value) || 0) + 1);
  }

  return Array.from(counts.entries())
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0], 'pt-BR'))
    .slice(0, limit)
    .map(([value, total]) => ({ value, total }));
}

function summarizeActivePropertiesCatalog(items) {
  const prices = items
    .map((item) => item.price)
    .filter((value) => Number.isFinite(value));

  return {
    total_ativos_em_contexto: items.length,
    faixa_preco: prices.length
      ? {
          minimo: Math.min(...prices),
          maximo: Math.max(...prices),
        }
      : null,
    cidades: countTopValues(items, (item) => item.features.city),
    bairros: countTopValues(items, (item) => item.features.neighborhood),
    tipos: countTopValues(items, (item) => item.features.property_type),
    exemplos: items.slice(0, 6).map((item) => ({
      id: item.id,
      title: item.title,
      slug: item.slug,
      public_url: item.public_url || null,
      cover_image: item.cover_image || null,
      address: item.address,
      price: item.price,
      property_offers: item.property_offers,
      city: item.features.city || null,
      neighborhood: item.features.neighborhood || null,
      property_type: item.features.property_type || null,
      bedrooms: item.features.bedrooms || null,
      bathrooms: item.features.bathrooms || null,
      parking: item.features.parking || null,
      built_area: item.features.built_area || null,
    })),
    observacao: 'Use as ferramentas seguras de Postgres para buscar, filtrar ou detalhar imoveis alem deste resumo.',
  };
}

