const reply = $('Prepare Reply').first().json;
const payload = $json || {};

function asTrimmedString(value) {
  return typeof value === 'string' && value.trim() ? value.trim() : null;
}

function parseArray(value) {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }
  return [];
}

function normalizeImageSource(value) {
  const image = asTrimmedString(value);
  if (!image) return null;
  if (/^https?:\/\//i.test(image)) return image;
  if (/^data:image\//i.test(image)) return image;
  return null;
}

const urls = [];
const seen = new Set();
const candidates = [
  ...parseArray(reply.media_urls),
  payload.cover_image,
  ...parseArray(payload.images),
];

for (const candidate of candidates) {
  const normalized = normalizeImageSource(candidate);
  if (!normalized || seen.has(normalized)) continue;
  seen.add(normalized);
  urls.push(normalized);
}

if (!urls.length) {
  return [{
    json: {
      ...reply,
      media_url: null,
      media_urls: [],
      media_caption: null,
      media_index: 0,
      media_total: 0,
      property_id: payload.property_id || null,
      property_title: payload.property_title || null,
    },
  }];
}

const caption = reply.media_caption || reply.text || null;

return urls.map((mediaUrl, index) => ({
  json: {
    ...reply,
    media_url: mediaUrl,
    media_urls: urls,
    media_caption: index === 0 ? caption : null,
    media_index: index,
    media_total: urls.length,
    property_id: payload.property_id || null,
    property_title: payload.property_title || null,
  },
}));
